// Digest: board name, group names, column titles+types, and 3 sample rows.
const b=((($input.first().json||{}).data||{}).boards||[])[0]||{};
const items=(b.items_page&&b.items_page.items)||[];
const cols={};
for(const it of items){for(const c of (it.column_values||[])){const t=(c.column&&c.column.title)||c.id;if(!cols[t])cols[t]=(c.column&&c.column.type)||'?';}}
const samples=items.slice(0,3).map(it=>({item:it.name,group:(it.group||{}).title,values:Object.fromEntries((it.column_values||[]).filter(c=>c.text).map(c=>[(c.column&&c.column.title)||c.id,c.text]))}));
return [{json:{board:b.name||'(not found - check board access)',rows_sampled:items.length,columns:cols,samples}}];
